class Solution(object):
    def equalFrequency(self, word):
        from collections import Counter
        char_count = Counter(word)
        for char in word:
            char_count[char] -= 1
            if char_count[char] == 0:
                del char_count[char]
            freq_count = Counter(char_count.values())
            if len(freq_count) == 1:
                freq = list(freq_count.keys())[0]
                if freq * len(char_count) == len(word) - 1:
                    return True
            char_count[char] += 1
        return False
